  {
    "id": 637,
    "text": "でも"
  },
  {
    "id": 638,
    "text": "、これからあるんだっていう"
  },
  {
    "id": 639,
    "text": "、"
  },
  {
    "id": 640,
    "text": "なんか"
  },
  {
    "id": 641,
    "text": "、"
  },
  {
    "id": 642,
    "text": "いろんな気持ちを込めて"
