    "id": 680,
    "text": "、"
  },
  {
    "id": 681,
    "text": "やっぱりあるんだなっていうのを思い出して"
  },
  {
    "id": 682,
    "text": "、"
  },
  {
    "id": 683,
    "text": "だからこそ"
  },
  {
    "id": 684,
    "text": "、幼少期のエナも"
  },
  {
    "id": 685,
    "text": "、演じさせていただいたんですけど"
  },
  {
    "id": 686,
    "text": "、"
  },
  {
    "id": 687,
    "text": "もう子供だから純粋だし"
  },
  {
    "id": 688,
    "text": "、"
  },
  {
    "id": 689,
    "text": "もう全部見えるものが新しくってキラキラ輝いてて"
  },
  {
    "id": 690,
    "text": "、"
  },
  {
    "id": 691,
    "text": "そんな世界の中に"
  },
  {
    "id": 692,
    "text": "、お父さんがいて"
