    "text": "、そのお父さんが"
  },
  {
    "id": 694,
    "text": "、"
  },
  {
    "id": 695,
    "text": "もっともっとエナにとってすごい人っていう"
  },
  {
    "id": 696,
    "text": "、"
  },
  {
    "id": 697,
    "text": "憧れの人"
