    "id": 1091,
    "text": "、あ"
  },
  {
    "id": 1092,
    "text": "、じゃあ"
  },
  {
    "id": 1093,
    "text": "、3DMVのちょっと感想をね"
  },
  {
    "id": 1094,
    "text": "、今更ですけど"
  },
  {
    "id": 1095,
    "text": "、言うとなんか元々フルで撮ってはいるけど"
  },
  {
    "id": 1096,
    "text": "、歌い分けはしているので"
  },
  {
    "id": 1097,
    "text": "、どこが絵奈パートになるかって"
  },
  {
    "id": 1098,
    "text": "。"
  },
  {
    "id": 1099,
    "text": "で"
  },
  {
    "id": 1100,
    "text": "、歌い出しが"
  },
  {
    "id": 1101,
    "text": "、あの"
  },
  {
    "id": 1102,
    "text": "、2号の3人から順に始まるので"
  },
  {
    "id": 1103,
    "text": "、なんか脳内の3DMV"
  },
  {
    "id": 1104,
    "text": "、私の妄想3DMVはあ絵奈じゃない"
  },
  {
    "id": 1105,
    "text": "、歌"
  },
  {
    "id": 1106,
    "text": "、なんかこうなんだろう"
  },
  {
    "id": 1107,
    "text": "、どうやって始まるんだろう"
  },
  {
    "id": 1108,
    "text": "、と思って"
  },
  {
    "id": 1109,
    "text": "、4人とか5人がこう"
  },
  {
    "id": 1110,
    "text": "、パッと映るのかこう"
  },
  {
    "id": 1111,
    "text": "、歌い出しの瑞希から始まるのか"
  },
  {
    "id": 1112,
    "text": "、と思っていたらなんかこう"
  },
  {
    "id": 1113,
    "text": "、絵奈がずっと映っていて"
  },
  {
    "id": 1114,
    "text": "、なんか"
  },
  {
    "id": 1115,
    "text": "、もちろんその分ね"
  },
  {
    "id": 1116,
    "text": "、あの"
  },
  {
    "id": 1117,
    "text": "、他のキャラクターを応援してくれてる方はその時はまたその子の映っているパーセンテージが高いと鈴木も嬉しいですけど"
  },
  {
    "id": 1118,
    "text": "、でもなんかこう"
  },
  {
    "id": 1119,
    "text": "、絵奈へのスポットがすごく多いMVで"
  },
  {
    "id": 1120,
    "text": "、なんかそれがすごくストーリーとマッチしていてなんか絵奈の生き様を映してくれているMVだな"
  },
  {
    "id": 1121,
    "text": "、と思って"
  },
  {
    "id": 1122,
    "text": "、すごく"
  },
  {
    "id": 1123,
    "text": "、あの"
  },
  {
    "id": 1124,
    "text": "、演者側として嬉しかった"
  },
  {
    "id": 1125,
    "text": "、っていうのがありましたね"
  },
  {
    "id": 1126,
    "text": "。"
  },
  {
    "id": 1127,
    "text": "絵が映ってるっていうのも"
  },
  {
    "id": 1128,
    "text": "、毎回そうなですけど"
  },
  {
    "id": 1129,
    "text": "、その絵奈のストーリーの時の楽曲がはなんか"
  },
  {
    "id": 1130,
    "text": "、ま"
  },
  {
    "id": 1131,
    "text": "、ちょっと場所もなんかちょっとずつ地上に上がってる感じもあるし"
  },
  {
    "id": 1132,
    "text": "、なんかそれも"
  },
  {
    "id": 1133,
    "text": "、ま"
  },
  {
    "id": 1134,
    "text": "、これはただのオタクの考察ですけど"
  },
  {
    "id": 1135,
    "text": "、なんかそういうのも嬉しかったりとか"
  },
  {
    "id": 1136,
    "text": "。"
  },
  {
    "id": 1137,
    "text": "でも"
  },
  {
    "id": 1138,
    "text": "、まだそんな数回"
  },
  {
    "id": 1139,
    "text": "、私も数回しか見れてないので"
  },
  {
    "id": 1140,
    "text": "、じっくり見たいなと思います"
